// --- Secure Key Management Abstraction ---

trait KeyStore {
  def storeKey(keyId: String, key: Array[Byte]): Unit
  def retrieveKey(keyId: String): Option[Array[Byte]]
  def deleteKey(keyId: String): Unit
}

/**
 * In production, replace this with integration to:
 * - AWS KMS / Secrets Manager
 * - HashiCorp Vault
 * - Azure Key Vault
 * - Google Cloud KMS
 * - Hardware Security Module (HSM)
 *
 * This in-memory implementation is for demonstration only.
 * Keys are stored in memory and never serialized to disk or config.
 */
class SecureKeyStore private () extends KeyStore {
  private val keys: TrieMap[String, Array[Byte]] = TrieMap.empty

  override def storeKey(keyId: String, key: Array[Byte]): Unit = {
    keys.put(keyId, key.clone())
  }

  override def retrieveKey(keyId: String): Option[Array[Byte]] = {
    keys.get(keyId).map(_.clone())
  }

  override def deleteKey(keyId: String): Unit = {
    keys.remove(keyId).foreach(k => java.util.Arrays.fill(k, 0.toByte))
  }
}

object SecureKeyStore {
  private val instance = new SecureKeyStore()
  def apply(): SecureKeyStore = instance
}

