// --- Secure Random Provider ---

object SecureRandomProvider {
  // ThreadLocal SecureRandom for thread safety without contention
  private val threadLocalRandom: ThreadLocal[SecureRandom] = ThreadLocal.withInitial(() => {
    // Use the strongest available SecureRandom implementation
    val sr = new SecureRandom()
    // Force seeding from OS entropy source
    sr.nextBytes(new Array[Byte](64))
    sr
  })

  def instance: SecureRandom = threadLocalRandom.get()

  /**
   * Generate cryptographically secure random bytes.
   */
  def generateBytes(length: Int): Array[Byte] = {
    require(length > 0, "Byte length must be positive")
    val bytes = new Array[Byte](length)
    instance.nextBytes(bytes)
    bytes
  }

  /**
   * Generate a URL-safe Base64 encoded random string.
   */
  def generateUrlSafeBase64(byteLength: Int): String = {
    val bytes = generateBytes(byteLength)
    Base64.getUrlEncoder.withoutPadding().encodeToString(bytes)
  }

  /**
   * Generate a hex-encoded random string.
   */
  def generateHex(byteLength: Int): String = {
    val bytes = generateBytes(byteLength)
    bytes.map(b => f"$b%02x").mkString
  }
}

// --- Hashing Utility (for storing token hashes) ---

object TokenHasher {
  import java.security.MessageDigest

  /**
   * Hash a token using SHA-256 for secure storage.
   * We store the hash in the session store, never the raw token.
   */
  def hashToken(token: String): String = {
    val digest = MessageDigest.getInstance("SHA-256")
    val hashBytes = digest.digest(token.getBytes("UTF-8"))
    hashBytes.map(b => f"$b%02x").mkString
  }

  /**
   * Constant-time comparison to prevent timing attacks.
   */
  def constantTimeEquals(a: String, b: String): Boolean = {
    if (a.length != b.length) return false
    var result = 0
    for (i <- a.indices) {
      result |= a.charAt(i) ^ b.charAt(i)
    }
    result == 0
  }
}

// --- Authenticated Encryption for Sensitive Token Payloads ---

object TokenEncryption {
  private val AES_GCM = "AES/GCM/NoPadding"
  private val GCM_TAG_LENGTH = 128 // bits
  private val GCM_IV_LENGTH = 12   // bytes (96 bits, recommended for GCM)
  private val KEY_SIZE = 256       // bits
  private val ENCRYPTION_KEY_ID = "token-encryption-master-key"

  /**
   * Initialize the encryption key and store it in the secure key store.
   * In production, this key would come from a KMS or HSM.
   */
  def initializeEncryptionKey(keyStore: KeyStore): Unit = {
    if (keyStore.retrieveKey(ENCRYPTION_KEY_ID).isEmpty) {
      val keyGen = KeyGenerator.getInstance("AES")
      keyGen.init(KEY_SIZE, SecureRandomProvider.instance)
      val secretKey = keyGen.generateKey()
      keyStore.storeKey(ENCRYPTION_KEY_ID, secretKey.getEncoded)
    }
  }

  /**
   * Encrypt data using AES-256-GCM (authenticated encryption).
   */
  def encrypt(plaintext: Array[Byte], keyStore: KeyStore, aad: Option[Array[Byte]] = None): Try[Array[Byte]] = Try {
    val keyBytes = keyStore.retrieveKey(ENCRYPTION_KEY_ID)
      .getOrElse(throw new SecurityException("Encryption key not found in key store"))
    val secretKey = new SecretKeySpec(keyBytes, "AES")

    val iv = SecureRandomProvider.generateBytes(GCM_IV_LENGTH)
    val gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv)

    val cipher = Cipher.getInstance(AES_GCM)
    cipher.init(Cipher.ENCRYPT_MODE, secretKey, gcmSpec)

    // Add Additional Authenticated Data if provided
    aad.foreach(cipher.updateAAD)

    val ciphertext = cipher.doFinal(plaintext)

    // Prepend IV to ciphertext: [IV (12 bytes)][Ciphertext + GCM Tag]
    iv ++ ciphertext
  }

  /**
   * Decrypt data using AES-256-GCM (authenticated encryption).
   */
  def decrypt(encryptedData: Array[Byte], keyStore: KeyStore, aad: Option[Array[Byte]] = None): Try[Array[Byte]] = Try {
    require(encryptedData.length > GCM_IV_LENGTH, "Encrypted data too short")

    val keyBytes = keyStore.retrieveKey(ENCRYPTION_KEY_ID)
      .getOrElse(throw new SecurityException("Encryption key not found in key store"))
    val secretKey = new SecretKeySpec(keyBytes, "AES")

    val iv = encryptedData.take(GCM_IV_LENGTH)
    val ciphertext = encryptedData.drop(GCM_IV_LENGTH)

    val gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv)
    val cipher = Cipher.getInstance(AES_GCM)
    cipher.init(Cipher.DECRYPT_MODE, secretKey, gcmSpec)

    aad.foreach(cipher.updateAAD)

    cipher.doFinal(ciphertext)
  }
}

// --- Session Store ---

class SessionStore {
  private val sessions: TrieMap[String, TokenMetadata] = TrieMap.empty

  def store(metadata: TokenMetadata): Unit = {
    sessions.put(metadata.tokenHash, metadata)
  }

  def lookup(tokenHash: String): Option[TokenMetadata] = {
    sessions.get(tokenHash).filterNot(m => m.isRevoked || m.expiresAt < System.currentTimeMillis())
  }

  def revoke(tokenHash: String): Boolean = {
    sessions.get(tokenHash) match {
      case Some(metadata) =>
        sessions.put(tokenHash, metadata.copy(isRevoked = true))
        true
      case None => false
    }
  }

  def revokeAllForUser(userId: String): Int = {
    val userSessions = sessions.filter(_._2.userId == userId)
    userSessions.foreach { case (hash, metadata) =>
      sessions.put(hash, metadata.copy(isRevoked = true))
    }
    userSessions.size
  }

  def cleanupExpired(): Int = {
    val now = System.currentTimeMillis()
    val expired = sessions.filter(_._2.expiresAt < now)
    expired.foreach { case (hash, _) => sessions.remove(hash) }
    expired.size
  }

  def activeSessionCount: Int = {
    val now = System.currentTimeMillis()
    sessions.count { case (_, m) => !m.isRevoked && m.expiresAt > now }
  }
}

// --- Token Generation Service ---

class TokenGenerationService(keyStore: KeyStore, sessionStore: SessionStore) {

  // Initialize encryption key on service startup
  TokenEncryption.initializeEncryptionKey(keyStore)

  /**
   * Generate a cryptographically secure session token.
   *
   * SECURITY NOTE: We use SecureRandom instead of scala.util.Random.
   * scala.util.Random uses java.util.Random (LCG) which is predictable.
   * An attacker observing a few tokens could predict all future tokens.
   */
  def generateSessionToken(userId: String): (String, TokenMetadata) = {
    generateToken(SessionToken, userId)
  }

  /**
   * Generate a cryptographically secure API key.
   */
  def generateApiKey(userId: String): (String, TokenMetadata) = {
    generateToken(ApiKey, userId)
  }

  /**
   * Generate a cryptographically secure refresh token.
   */
  def generateRefreshToken(userId: String): (String, TokenMetadata) = {
    generateToken(RefreshToken, userId)
  }

  /**
   * Generate a cryptographically secure CSRF token.
   */
  def generateCsrfToken(userId: String): (String, TokenMetadata) = {
    generateToken(CsrfToken, userId)
  }

  /**
   * Core token generation using cryptographically secure randomness.
   */
  private def generateToken(tokenType: TokenType, userId: String): (String, TokenMetadata) = {
    // Generate cryptographically secure random bytes
    val randomPart = SecureRandomProvider.generateUrlSafeBase64(tokenType.byteLength)

    // Format: prefix_randomPart
    val token = s"${tokenType.prefix}_$randomPart"

    val now = System.currentTimeMillis()
    val metadata = TokenMetadata(
      tokenHash = TokenHasher.hashToken(token),
      tokenType = tokenType,
      userId = userId,
      createdAt = now,
      expiresAt = now + (tokenType.ttlSeconds * 1000)
    )

    // Store the hash, never the raw token
    sessionStore.store(metadata)

    (token, metadata)
  }

  /**
   * Validate a token by hashing it and looking up the hash.
   */
  def validateToken(rawToken: String): Option[TokenMetadata] = {
    val tokenHash = TokenHasher.hashToken(rawToken)
    sessionStore.lookup(tokenHash)
  }

  /**
   * Validate a token with constant-time comparison.
   */
  def validateTokenSecure(rawToken: String, expectedHash: String): Boolean = {
    val computedHash = TokenHasher.hashToken(rawToken)
    TokenHasher.constantTimeEquals(computedHash, expectedHash)
  }

  /**
   * Revoke a specific token.
   */
  def revokeToken(rawToken: String): Boolean = {
    val tokenHash = TokenHasher.hashToken(rawToken)
    sessionStore.revoke(tokenHash)
  }

  /**
   * Revoke all sessions for a user (e.g., on password change).
   */
  def revokeAllUserSessions(userId: String): Int = {
    sessionStore.revokeAllForUser(userId)
  }

  /**
   * Generate an encrypted token payload (for tokens that carry data).
   */
  def generateEncryptedToken(userId: String, payload: String): Try[String] = {
    val aad = userId.getBytes("UTF-8")
    TokenEncryption.encrypt(payload.getBytes("UTF-8"), keyStore, Some(aad)).map { encrypted =>
      Base64.getUrlEncoder.withoutPadding().encodeToString(encrypted)
    }
  }

  /**
   * Decrypt and verify an encrypted token payload.
   */
  def decryptToken(encryptedToken: String, userId: String): Try[String] = {
    Try(Base64.getUrlDecoder.decode(encryptedToken)).flatMap { encrypted =>
      val aad = userId.getBytes("UTF-8")
      TokenEncryption.decrypt(encrypted, keyStore, Some(aad)).map(new String(_, "UTF-8"))
    }
  }
}

